      `C ${fmt(tx(163))} ${fmt(ty(195))} ${fmt(tx(166))} ${fmt(ty(198))} ${fmt(tx(171))} ${fmt(ty(198))}`,
      `C ${fmt(tx(180))} ${fmt(ty(198))} ${fmt(tx(187))} ${fmt(ty(190))} ${fmt(tx(187))} ${fmt(ty(177))}`,
      `C ${fmt(tx(187))} ${fmt(ty(190))} ${fmt(tx(194))} ${fmt(ty(198))} ${fmt(tx(203))} ${fmt(ty(198))}`,
      `C ${fmt(tx(208))} ${fmt(ty(198))} ${fmt(tx(211))} ${fmt(ty(195))} ${fmt(tx(211))} ${fmt(ty(192))}`,
      `C ${fmt(tx(211))} ${fmt(bottomY - bd * .15)} ${fmt(cx + bottomW)} ${fmt(bottomY)} ${fmt(cx)} ${fmt(bottomY)}`,
      `C ${fmt(cx - bottomW)} ${fmt(bottomY)} ${fmt(tx(163))} ${fmt(bottomY - bd * .15)} ${fmt(tx(163))} ${fmt(ty(192))} Z`
    ].join(" ");
  }
  function mouthCavityD(open) {
    const cx = SURPRISE_MOUTH.cx;
    const cy = SURPRISE_MOUTH.cavityY;
    const w = SURPRISE_MOUTH.cavityW * (.72 + .28 * open);
    const h = SURPRISE_MOUTH.cavityH * (.68 + .32 * open);
    return [
      `M ${fmt(cx - w)} ${fmt(cy)}`,
      `C ${fmt(cx - w)} ${fmt(cy - h * .55)} ${fmt(cx + w)} ${fmt(cy - h * .55)} ${fmt(cx + w)} ${fmt(cy)}`,
      `C ${fmt(cx + w)} ${fmt(cy + h * .66)} ${fmt(cx - w)} ${fmt(cy + h * .66)} ${fmt(cx - w)} ${fmt(cy)} Z`
    ].join(" ");
  }
  function mouthLowerCavityD(open) {
    const progress = SURPRISE_MOUTH.maxProgress * clamp(open, 0, 1);
    const tp = clamp((progress - 18) / 82, 0, 1);
    const cx = SURPRISE_MOUTH.cx;
    const y = SURPRISE_MOUTH.lowerCavityY;
    const lcw = Math.max(.1, SURPRISE_MOUTH.lowerCavityW * tp);
    const lch = Math.max(.1, SURPRISE_MOUTH.lowerCavityH * tp);
    const tail = 46 + SURPRISE_MOUTH.bottomDrop;
    return [
      `M ${fmt(cx - lcw)} ${fmt(y)}`,
      `C ${fmt(cx - lcw * .82)} ${fmt(y - lch)} ${fmt(cx + lcw * .82)} ${fmt(y - lch)} ${fmt(cx + lcw)} ${fmt(y)}`,
      `L ${fmt(cx + lcw * 1.28)} ${fmt(y + tail)}`,
      `L ${fmt(cx - lcw * 1.28)} ${fmt(y + tail)} Z`
    ].join(" ");
  }
  function applyMouthPose(open) {
    const interior = svg.querySelector("#mouth-interior-clipped");
    const clipPath = svg.querySelector("#mouth-opening-clip-path");
    const cavity = svg.querySelector("#mouth-cavity-fill");
    const lower = svg.querySelector("#mouth-lower-cavity-fill");
    if (!interior || !clipPath || !cavity || !lower) return;
    if (open <= .01) { interior.style.display = "none"; return; }
    interior.style.display = "";
    interior.setAttribute("opacity", fmt(.72 + .28 * open));
    clipPath.setAttribute("d", mouthOpeningClipD(open));
    cavity.setAttribute("d", mouthCavityD(open));
    lower.setAttribute("d", mouthLowerCavityD(open));
  }
  // thinking 定稿闭嘴收口搬运：母版嘴 d 不动，stroke-dasharray 从外端裁短
  // （源 = hamster-thinking-loop-v1.svg applyMouthMaskMotion，inset 语义一致）
  function applyMouthInset(inset) {
    ["mouth-left", "mouth-right"].forEach((id) => {
      const node = svg.querySelector(`#${id}`);
      if (!node || !node.getTotalLength) return;
      if (inset <= .01) {
        node.removeAttribute("stroke-dasharray");
        node.removeAttribute("stroke-dashoffset");
        return;
      }
      const length = node.getTotalLength();
      const visibleLength = Math.max(.1, length - inset);
      node.setAttribute("stroke-dasharray", `${fmt(visibleLength)} ${fmt(length + 24)}`);
      node.setAttribute("stroke-dashoffset", "0");
    });
  }

  // ── 感叹号（notification confirmed drawNotificationExclamation 搬运；呼吸涨缩版）──
  const exLayer = document.getElementById("alert-exclamation-layer");
  function drawAlertExclamation(mark) {
    exLayer.textContent = "";
    if (mark.opacity <= .01) return;
    const stemTop = EXCLAMATION.stemTop;
    const stemBottom = EXCLAMATION.stemBottom;
    const stemHeight = Math.max(8, Math.abs(stemBottom - stemTop));
    const bend = clamp(stemHeight * .1, 2.2, 4.8);
    const stemMidA = stemTop + stemHeight * .34;
    const stemMidB = stemTop + stemHeight * .72;
    const stemWidth = EXCLAMATION.stemWidth;
    const outlineWidth = stemWidth + 6;
    const haloWidth = stemWidth + 12;
    const dotY = EXCLAMATION.dotY;
    const dotR = EXCLAMATION.dotR;
    const group = el("g", {
      id: "mini-alert-exclamation-mark",
      transform: `translate(${fmt(mark.x)} ${fmt(mark.y)}) rotate(${fmt(mark.rotate)}) scale(${fmt(mark.scale)})`,
      opacity: fmt(mark.opacity)
    });
    const stemD = `M 0 ${fmt(stemTop)} C ${fmt(bend)} ${fmt(stemMidA)} ${fmt(bend * .7)} ${fmt(stemMidB)} 0 ${fmt(stemBottom)}`;
    group.appendChild(el("path", { d: stemD, fill: "none", stroke: EXCLAMATION.halo, "stroke-width": fmt(haloWidth), "stroke-linecap": "round", opacity: fmt(EXCLAMATION.haloOpacity) }));
    group.appendChild(el("circle", { cx: "0", cy: fmt(dotY), r: fmt(dotR + 6), fill: EXCLAMATION.halo, opacity: fmt(EXCLAMATION.haloOpacity * .92) }));
    group.appendChild(el("path", { d: stemD, fill: "none", stroke: EXCLAMATION.stroke, "stroke-width": fmt(outlineWidth), "stroke-linecap": "round", "stroke-linejoin": "round" }));
    group.appendChild(el("path", { d: stemD, fill: "none", stroke: EXCLAMATION.fill, "stroke-width": fmt(stemWidth), "stroke-linecap": "round", "stroke-linejoin": "round" }));
    group.appendChild(el("path", {
      d: `M ${fmt(bend * .85)} ${fmt(stemTop + 5)} C ${fmt(bend + 1)} ${fmt(stemMidA)} ${fmt(bend * .75)} ${fmt(stemMidB - 2)} ${fmt(bend * .38)} ${fmt(stemBottom - 4)}`,
      fill: "none", stroke: EXCLAMATION.highlight, "stroke-width": fmt(Math.max(1.7, stemWidth * .3)), "stroke-linecap": "round", opacity: ".75"
    }));
    group.appendChild(el("circle", { cx: "0", cy: fmt(dotY), r: fmt(dotR + 2.6), fill: EXCLAMATION.stroke }));
    group.appendChild(el("circle", { cx: "0", cy: fmt(dotY), r: fmt(dotR), fill: EXCLAMATION.fill }));
    group.appendChild(el("circle", { cx: fmt(-dotR * .3), cy: fmt(dotY - dotR * .38), r: fmt(Math.max(1, dotR * .25)), fill: EXCLAMATION.highlight, opacity: ".85" }));
    exLayer.appendChild(group);
  }

  // ── 音波（cloudling mini-alert 弧段脉冲机制；圆心=耳朵屏幕位；回头后才发）──
  // 母版耳心经 rotate(-90 187 230)：上耳(母版右耳 286,73)→(30,131)，下耳(母版左耳 101,73)→(30,316)
  const EAR_CENTERS = [{ x: 30, y: 131 }, { x: 30, y: 316 }];
  const RIPPLE = {
    startRadius: 42, lifetime: 1.05, strokeW: 5,
    segments: [[148, 212], [98, 134], [226, 262]]  // 朝屏幕内(180°)的断续弧段
  };
  const ripLayer = document.getElementById("alert-ripple-layer");
  let ripples = [];
  let rippleSeq = 0;
  function polarPoint(cx, cy, r, deg) {
    const a = deg * Math.PI / 180;
    return [cx + Math.cos(a) * r, cy + Math.sin(a) * r];
  }
  function arcPath(cx, cy, r, a0, a1) {
    const [x0, y0] = polarPoint(cx, cy, r, a0);
    const [x1, y1] = polarPoint(cx, cy, r, a1);
    const large = Math.abs(a1 - a0) > 180 ? 1 : 0;
    return `M${fmt(x0)} ${fmt(y0)} A${fmt(r)} ${fmt(r)} 0 ${large} 1 ${fmt(x1)} ${fmt(y1)}`;
  }
  function easeOutCubic(x) { return 1 - Math.pow(1 - clamp(x, 0, 1), 3); }
  function emitRipple(strength, animT) {
    ripples.push({ id: ++rippleSeq, born: animT, strength });
  }
  function renderRipples(animT) {
    ripples = ripples.filter((r) => animT - r.born < RIPPLE.lifetime);
    let html = "";
    const palette = RIPPLE_PALETTES[state.ripPalette] || RIPPLE_PALETTES[0];
    const earCount = clamp(Math.round(state.ripEars), 1, 2);
    for (const rip of ripples) {
      const t = clamp((animT - rip.born) / RIPPLE.lifetime, 0, 1);
      const r = RIPPLE.startRadius + (state.ripMax - RIPPLE.startRadius) * easeOutCubic(t);
      const fadeIn = Math.min(1, (animT - rip.born) / 0.05);
      const fade = Math.pow(1 - t, 1.35) * fadeIn;
      const wobble = ((rip.id % 3) - 1) * 8;
      for (let e = 0; e < earCount; e += 1) {
        const c = EAR_CENTERS[e];
        for (let i = 0; i < RIPPLE.segments.length; i += 1) {
          const [a0, a1] = RIPPLE.segments[i];
          const d = arcPath(c.x, c.y, r + (i % 2) * 2.4, a0 + wobble, a1 + wobble);
          const op = state.ripOpacity * rip.strength * fade * (1 - i * .12);
          if (op < .015) continue;
          html += `<path d="${d}" fill="none" stroke="${palette.under}" stroke-width="${fmt(RIPPLE.strokeW + 2.6)}" stroke-linecap="round" stroke-opacity="${fmt(op * .45)}"/>`;
          html += `<path d="${d}" fill="none" stroke="${palette.main}" stroke-width="${fmt(RIPPLE.strokeW)}" stroke-linecap="round" stroke-opacity="${fmt(op)}"/>`;
        }
      }
    }
    ripLayer.innerHTML = html;
  }
  let lastEmitCycle = -1;

  // ── 视线喂点（mini-idle 引擎接口；剧本驱动，hover 已被 pointer-events:none 掐掉）──
  // lookAmount 0..1：0=看观众(正脸)，1=看感叹号方向(幅度由 lookYaw/lookPitch 滑块定)。
  // 感叹号在屏幕上方偏内 → master 系 yaw+ / pitch-（mini-idle 真机验证语义）。
  function feedLook(lookAmount) {
    if (typeof window.__cloudlingSetPointer !== "function") return;
    const masterX = LOOK.centerX + state.lookYaw * lookAmount * LOOK.halfW;
    const masterY = LOOK.centerY - state.lookPitch * lookAmount * LOOK.halfH;
    // master → mini 屏幕坐标（rotate(-90 187 230) 正变换）
    const miniX = masterY - 43;
    const miniY = 417 - masterX;
    window.__cloudlingSetPointer({ x: miniX, y: miniY, inside: true });
  }

  // ── 每帧应用 ──
  function setT(id, transform) {
    const node = svg.querySelector(`#${id}`);
    if (node) {
      if (transform) node.setAttribute("transform", transform);
      else node.removeAttribute("transform");
    }
  }

  let t0 = performance.now();
  function frame(now) {
    const t = (now - t0) / 1000 * state.speed;
    const { t1, t2, t3, t4, holdStart } = timeline();

    // 感叹号：冒出（线性喂 easeOutBack 过冲 + 从下往上升）→ 呼吸涨缩 → 回头时消失（戏演完退场）
    const popT = clamp(t / t1, 0, 1);
    const popScale = easeOutBack(popT);
    const popRise = (1 - popT) * 16;            // 从低 16px「冒」上来
    const breathT = Math.max(0, t - t1);
    const breathWave = Math.sin(2 * Math.PI * breathT / state.exBreathPeriod);
    const breathScale = 1 + state.exBreath * breathWave;
    const breathDy = 1.5 * Math.sin(2 * Math.PI * breathT / state.exBreathPeriod - .6);
    const exFade = 1 - smoothRange(t3, t3 + .4, t);  // 回头段淡出 + 缩没
    drawAlertExclamation({
      x: state.exX,
      y: state.exY + popRise + (t > t1 ? breathDy : 0),
      scale: state.exScale * popScale * (t > t1 ? breathScale : 1) * lerp(.55, 1, exFade),
      rotate: state.exRot + (1 - popT) * -10,
      opacity: smoothRange(0, .22, t) * exFade
    });

    // 视线（鹿鹿三轮：快速转头）：t1 一步阶跃喂终点，引擎 150ms 短段插值自身就是快转
    // （host 离散 pointer 同款行为；连续轨迹反而会被每帧重置插值的指数阻尼拖慢——实测踩坑）
    const lookAmount = (t >= t1 && t < t3) ? 1 : 0;
    feedLook(lookAmount);

    // 嘴（鹿鹿三轮口径）：转头到位后才张嘴——快张(0.16s)→停一拍→快闭(0.18s)，闭的同时直接收成 thinking 小嘴
    const open = smoothRange(t2, t2 + .16, t) * (1 - smoothRange(t2 + .42, t2 + .6, t));
    applyMouthPose(open);
    // 保持段嘴角微动：thinking 同款 inset 呼吸波动（中值 mouthInset、±2.5、周期 4s；sin 从 0 起与闭嘴终值无缝衔接）
    const insetBase = state.mouthInset * smoothRange(t2 + .42, t2 + .62, t);
    const insetWave = 2.5 * Math.sin(2 * Math.PI * (t - holdStart) / 4) * smoothRange(holdStart, holdStart + .3, t);
    applyMouthInset(Math.max(0, insetBase + insetWave));

    // 眉毛：快转瞬间惊弹（快弹快回）；闭嘴时切到 notification 认真眉并一直保持（认真脸）
    const browLiftY = state.browLift * smoothRange(t1 + .02, t1 + .18, t) * (1 - smoothRange(t2 + .35, t2 + .65, t));
    const browFocus = smoothRange(t2 + .4, t2 + .7, t);
    const browT = browLiftY > .01 ? `translate(0 ${fmt(-browLiftY)})` : "";
    setT("left-brow", browT);
    setT("right-brow", browT);
    const lb = svg.querySelector("#left-brow");
    const rb = svg.querySelector("#right-brow");
    if (lb) lb.setAttribute("d", lerpPathNumbers(BROW_POSES.leftNeutral, BROW_POSES.leftFocus, browFocus));
    if (rb) rb.setAttribute("d", lerpPathNumbers(BROW_POSES.rightNeutral, BROW_POSES.rightFocus, browFocus));

    // 墨镜惊跳：随快转同步（写 wrapper，#sunglasses 自己归引擎弹簧缓动管）
    const glassY = -state.glassJump * smoothRange(t1 + .02, t1 + .14, t) * (1 - smoothRange(t1 + .18, t1 + .5, t));
    setT("alert-glasses-jump", Math.abs(glassY) > .02 ? `translate(0 ${fmt(glassY)})` : "");

    // 呆毛：快竖 → 回头时回落重力角；保持段叠轻飘（两根错相 0.8Hz，鹿鹿三轮：小闹钟别呆板）
    const perk = smoothRange(t1 + .02, t1 + .18, t) * (1 - smoothRange(t3, t3 + .5, t));
    const floatRamp = smoothRange(holdStart, holdStart + .3, t);
    const floatL = Math.sin(2 * Math.PI * .8 * (t - holdStart)) * state.tuftFloat * floatRamp;
    const floatR = Math.sin(2 * Math.PI * .8 * (t - holdStart) + .9) * state.tuftFloat * floatRamp;
    const tuftBase = lerp(-32, state.tuftPerk, perk);
    setT("left-tuft", `rotate(${fmt(tuftBase + floatL)} 182 49)`);
    setT("right-tuft", `rotate(${fmt(tuftBase + floatR)} 200 50)`);

    // 保持段闹铃摆：头部 wrapper 绕脖根小幅往复（鹿鹿口径「像小闹铃晃来晃去」，配音波=响铃中）
    const swayRamp = smoothRange(holdStart, holdStart + .2, t);
    const swayAngle = swayRamp > 0
      ? Math.sin(2 * Math.PI * state.swayFreq * (t - holdStart)) * state.swayAmp * swayRamp
      : 0;
    setT("alert-head-sway", Math.abs(swayAngle) > .02 ? `rotate(${fmt(swayAngle)} ${SWAY_PIVOT.x} ${SWAY_PIVOT.y})` : "");

    // 音波：鹿鹿口径「回头后再音波」——holdStart 起每周期一波，入场剧场段零波纹
    if (t >= holdStart) {
      const cycle = Math.floor((t - holdStart) / state.ripPeriod);
      if (cycle > lastEmitCycle) { lastEmitCycle = cycle; emitRipple(.85, t); }
    }
    renderRipples(t);

    // tuner 看片便利：保持段播够 4.5s 自动重播整段剧场
    if (autoLoop && t >= holdStart + 4.5) resetPlayback();

    refreshJson();
    requestAnimationFrame(frame);
  }

  function resetPlayback() {
    t0 = performance.now();
    ripples = [];
    lastEmitCycle = -1;
    feedLook(0);
  }

  function refreshJson() {} // 面板已剥离(导出无 tuner)

  prepareMouthRig();
  resetPlayback();
  requestAnimationFrame(frame);
  window.__miniAlert = { state, replay: resetPlayback };
})();
